import org.junit.jupiter.api.Test;
import static org.junit.jupiter.api.Assertions.*;

public class SolutionTest {

    @Test
    void classic() {
        // Arrow at 6 hits [1,6],[2,8]; arrow at 12 hits [7,12],[10,16]
        assertEquals(2, new Solution().findMinArrows(new int[][]{{10,16},{2,8},{1,6},{7,12}}));
    }

    @Test
    void allDisjoint() {
        // [1,2],[3,4],[5,6] — no shared points, need 3 arrows
        assertEquals(3, new Solution().findMinArrows(new int[][]{{1,2},{3,4},{5,6}}));
    }

    @Test
    void endpointTouchAllowsSharedArrow() {
        // [1,2] and [2,3] share endpoint 2 — one arrow at 2 bursts both; [3,4] needs its own
        assertEquals(2, new Solution().findMinArrows(new int[][]{{1,2},{2,3},{3,4}}));
    }

    @Test
    void allCoveredByOne() {
        // [2,5] is inside [1,10] and [3,8] — one arrow at 5 hits all
        assertEquals(1, new Solution().findMinArrows(new int[][]{{1,10},{2,5},{3,8}}));
    }

    @Test
    void singleBalloon() {
        assertEquals(1, new Solution().findMinArrows(new int[][]{{3,9}}));
    }

    @Test
    void emptyInput() {
        assertEquals(0, new Solution().findMinArrows(new int[][]{}));
    }

    @Test
    void duplicateBalloons() {
        // Three identical balloons [1,5] — one arrow at 5 bursts all
        assertEquals(1, new Solution().findMinArrows(new int[][]{{1,5},{1,5},{1,5}}));
    }
}
